import{_ as i,c as e,o as l,a}from"./app.23021918.js";const r=JSON.parse('{"title":"코드앤버터 소개","description":"","frontmatter":{"head":[["meta",{"property":"og:description","content":"코드앤버터 소개"}],["meta",{"property":"twitter:description","content":"코드앤버터 소개"}]]},"headers":[{"level":2,"title":"주요기능","slug":"주요기능"},{"level":2,"title":"역할","slug":"역할"},{"level":2,"title":"앞으로","slug":"앞으로"},{"level":2,"title":"더 알아보기","slug":"더-알아보기"}],"relativePath":"guide/intro.md"}'),t={name:"guide/intro.md"},s=[a('<h1 id="코드앤버터-소개" tabindex="-1">코드앤버터 소개 <a class="header-anchor" href="#코드앤버터-소개" aria-hidden="true">#</a></h1><p><strong>웹사이트를 꾸미는 가장 쉬운 방법</strong> 🧈 코드앤버터</p><p>코드앤버터는 누구나 쉽고 예쁘게 사이트를 꾸밀 수 있도록 도와주는 서비스입니다.<br> 코드앤버터에서 팝업을 만들고 웹사이트에 스크립트를 추가하면 바로 사용할 수 있습니다. <s>참 쉽죠?</s></p><h2 id="주요기능" tabindex="-1">주요기능 <a class="header-anchor" href="#주요기능" aria-hidden="true">#</a></h2><ul><li><strong>🪄 NOCODE</strong> 코드를 몰라도 원하는 템플릿을 선택하고 드래그앤드롭으로 팝업을 만들 수 있습니다.</li><li><strong>🎨 CUSTOMIZING</strong> 팝업의 위치, 크기, 색상, 내용, 노출 시간, 노출 페이지등을 설정할 수 있습니다.</li><li><strong>😀 FLEXIBILITY</strong> 스크립트를 추가하는 방식으로 대부분의 라이브러리, 프레임워크, 서비스에 손쉽게 사용할 수 있습니다.</li><li><strong>📈 OPTIMIZE</strong> 페이지뷰, 세션뷰와 같은 통계를 확인할 수 있습니다.</li><li>👋 그 외에 필요한 기능이 있으면 요청해주세요. 저희가 대신 만들어 드립니다. 😃</li></ul><h2 id="역할" tabindex="-1">역할 <a class="header-anchor" href="#역할" aria-hidden="true">#</a></h2><p>코드앤버터는 기존 서비스에 자연스럽게 추가할 수 있는 컴포넌트를 만듭니다.</p><p>이미 많은 곳에서 지도, 우편번호 검색, 방문자 분석, 채팅, 설문조사 같은 서비스를 연동합니다.<br> 이렇게 특별한 목적으로 외부 서비스를 사용하는 경우는 많지만, 팝업, 배너, 공지사항, 게시판, FAQ, 이벤트 페이지 등은 자체 개발하는 경우가 많습니다.<br> 페이지를 구성하는 여러 요소를 <strong>필요할 때 가져다 사용</strong>할 수 있다면 개발자는 더 효율적으로 핵심 비지니스 로직에 집중할 수 있습니다.</p><h2 id="앞으로" tabindex="-1">앞으로 <a class="header-anchor" href="#앞으로" aria-hidden="true">#</a></h2><p>팝업을 시작으로 앞으로 계획은 다음과 같습니다.</p><ul><li>피드백 개선 개선 개선!</li><li>플랫폼 자동 연동 지원</li><li>더 많은 컴포넌트 지원</li><li>Headless CMS 연동</li><li>React.js/Vue.js 라이브러리 제공</li><li>템플릿/컴포넌트를 사고 팔 수 있는 스토어 개발</li><li>마케팅, 퍼포먼스 분석 기능 추가</li><li>필요한 컴포넌트를 더 쉽고 빠르게 만들 수 있는 AI / 자동 최적화 기능 강화</li><li>엔터프라이즈 수준 보안 강화 (2차 인증, SAML 연동, ...)</li><li>오픈 API / Webhook 제공</li><li>실시간 협업 기능 추가</li><li>...? 😎</li></ul><h2 id="더-알아보기" tabindex="-1">더 알아보기 <a class="header-anchor" href="#더-알아보기" aria-hidden="true">#</a></h2><ul><li><a href="./vs-other-apps.html">다른 도구와 비교하기</a></li><li><a href="./basic.html">팝업 만들기 가이드 보기</a></li><li><a href="./faq.html">자주 묻는 질문 안내</a></li></ul>',13)];var n=i(t,[["render",function(i,a,r,t,n,h){return l(),e("div",null,s)}]]);export{r as __pageData,n as default};
